parameters.jsCode:
const items = $input.all();

return items.map(item => {
  let content = '';

  // Extrair texto da resposta OpenAI (suporta múltiplos formatos de resposta)
  if (item.json.message?.content) {
    content = item.json.message.content;
  } else if (item.json.choices?.[0]?.message?.content) {
    content = item.json.choices[0].message.content;
  } else if (typeof item.json.content === 'string') {
    content = item.json.content;
  } else if (Array.isArray(item.json.content)) {
    content = item.json.content.map(c => c.text || '').join('');
  }

  try {
    // Remover blocos de markdown se presente
    content = content.replace(/```json\n?/gi, '').replace(/```\n?/gi, '').trim();
    // Extrair apenas o JSON se houver texto antes ou depois
    const jsonMatch = content.match(/\{[\s\S]*\}/);
    if (jsonMatch) content = jsonMatch[0];

    const parsed = JSON.parse(content);

    return { 
      json: {
        intencao: parsed.intencao || 'duvida',
        nome: parsed.nome || null,
        telefone: parsed.telefone || null,
        servico: parsed.servico || null,
        data: parsed.data || null,
        horario: parsed.horario || null,
        nova_data: parsed.nova_data || null,
        novo_horario: parsed.novo_horario || null,
        mensagem_original: parsed.mensagem_original || content,
        dados_completos: parsed.dados_completos === true
      }
    };
  } catch (e) {
    // Fallback em caso de erro de parsing
    return {
      json: {
        intencao: 'duvida',
        nome: null,
        telefone: null,
        servico: null,
        data: null,
        horario: null,
        nova_data: null,
        novo_horario: null,
        mensagem_original: content,
        dados_completos: true,
        _parse_error: e.message
      }
    };
  }
});

