    resposta = item.json.message.content;
  } else if (item.json.choices?.[0]?.message?.content) {
    resposta = item.json.choices[0].message.content;
  } else if (typeof item.json.content === 'string') {
    resposta = item.json.content;
  } else {
    resposta = 'Desculpe, não consegui processar sua dúvida no momento. Por favor, entre em contato diretamente com a clínica para mais informações.';
