parameters.jsCode:
const body = $input.first().json.body || $input.first().json;

const session_id = body.session_id || body.from || 'session-' + Date.now();
const contact_phone = body.phone || body.from || body.contact_phone || '';
const contact_name = body.name || body.contact_name || 'Cliente';
const message_type = body.type || body.message_type || 'text';
let message_content = '';

if (message_type === 'text') {
  message_content = body.text?.body || body.message || body.content || '';
} else if (message_type === 'image') {
  message_content = body.image?.url || body.media_url || '';
} else if (message_type === 'audio') {
  message_content = body.audio?.url || body.media_url || '';
}

return [{
  json: {
    session_id,
    contact_phone,
    contact_name,
    message_type,
    message_content,
    timestamp: new Date().toISOString()
  }
}];

const sessionData = $('2. Verificar Modo Humano').first()?.json || {};
const inputData = $('Parsear Mensagem').first().json;

const humanTakeover = sessionData.human_takeover || false;
const takeoverAt = sessionData.takeover_at ? new Date(sessionData.takeover_at) : null;
const now = new Date();

let status = 'ia';

if (humanTakeover && takeoverAt) {
  const secondsElapsed = (now - takeoverAt) / 1000;
  if (secondsElapsed < 60) {
    status = 'human_active';
  } else {
    status = 'reset_to_ia';
  }
}

return [{
  json: {
    ...inputData,
    session_exists: !!sessionData.session_id,
    human_status: status
  }
}];

const clientRows = $('3. Verificar Cliente').all();
const inputData = $('Lógica Modo Humano').first().json;

let client_id;
let is_new_client = false;

if (clientRows.length > 0 && clientRows[0].json.id) {
  client_id = clientRows[0].json.id;
} else {
  is_new_client = true;
}

return [{
  json: {
    ...inputData,
    client_id: client_id || null,
    is_new_client
  }
}];

const inputData = $('Lógica Cliente Novo ou Existente').first().json;
let client_id = inputData.client_id;

try {
  const newClient = $('Cadastrar Novo Cliente').first();
  if (newClient?.json?.id) {
    client_id = newClient.json.id;
  }
} catch(e) {}

return [{
  json: {
    ...inputData,
    client_id
  }
}];

const historyRows = $('4. Carregar Histórico').all();
const inputData = $('Unificar client_id').first().json;

const history = historyRows
  .map(row => row.json)
  .reverse()
  .map(msg => `${msg.role === 'user' ? 'Cliente' : 'Assistente'}: ${msg.content}`)
  .join('\n');

return [{
  json: {
    ...inputData,
    conversation_history: history || 'Início da conversa.'
  }
}];

const inputData = $('Formatar Histórico').first().json;
let processed_message = inputData.message_content;

try {
  const visionResult = $('Processar Imagem — Vision').first();
  if (visionResult?.json?.choices?.[0]?.message?.content) {
    processed_message = '[Imagem recebida] ' + visionResult.json.choices[0].message.content;
  }
} catch(e) {}

try {
  const whisperResult = $('Transcrever Áudio — Whisper').first();
  if (whisperResult?.json?.text) {
    processed_message = '[Áudio transcrito] ' + whisperResult.json.text;
  }
} catch(e) {}

return [{
  json: {
    ...inputData,
    processed_message
  }
}];

const aiResponse = $('6. Agente IA').first().json;
const inputData = $('Unificar Mensagem Processada').first().json;

const fullText = aiResponse.choices?.[0]?.message?.content || 'Desculpe, não consegui processar sua mensagem.';

const needsHuman = fullText.includes('[HUMANO_NECESSÁRIO]');
const cleanText = fullText
  .replace('[HUMANO_NECESSÁRIO]', '')
  .trim();

// Detectar agendamento
let appointment_action = null;
const agendMatch = cleanText.match(/\[AGENDAMENTO: especialidade=([^,]+), data=([\d-]+), horario=([\d:]+)\]/);
const cancelMatch = cleanText.match(/\[CANCELAMENTO: appointment_id=([^\]]+)\]/);
const reagendMatch = cleanText.match(/\[REAGENDAMENTO: appointment_id=([^,]+), data=([\d-]+), horario=([\d:]+)\]/);

if (agendMatch) {
  appointment_action = {
    type: 'schedule',
    specialty: agendMatch[1].trim(),
    date: agendMatch[2],
    time: agendMatch[3]
  };
} else if (cancelMatch) {
  appointment_action = {
    type: 'cancel',
    appointment_id: cancelMatch[1].trim()
  };
} else if (reagendMatch) {
  appointment_action = {
    type: 'reschedule',
    appointment_id: reagendMatch[1].trim(),
    date: reagendMatch[2],
    time: reagendMatch[3]
  };
}

const finalText = cleanText
  .replace(/\[AGENDAMENTO:[^\]]+\]/g, '')
  .replace(/\[CANCELAMENTO:[^\]]+\]/g, '')
  .replace(/\[REAGENDAMENTO:[^\]]+\]/g, '')
  .trim();

const messages = finalText.split('[QUEBRA]').map(m => m.trim()).filter(Boolean);

return [{
  json: {
    ...inputData,
    ai_full_response: finalText,
    response_messages: messages,
    needs_human: needsHuman,
    appointment_action
  }
}];

const data = $input.first().json;
const action = data.appointment_action;

let query = '';

if (action.type === 'schedule') {
  query = `INSERT INTO appointments (client_id, specialty, appointment_date, appointment_time, status, created_at)
  VALUES ('${data.client_id}', '${action.specialty}', '${action.date}', '${action.time}', 'scheduled', NOW())`;
} else if (action.type === 'cancel') {
  query = `UPDATE appointments SET status = 'cancelled', updated_at = NOW() WHERE id = '${action.appointment_id}' AND client_id = '${data.client_id}'`;
} else if (action.type === 'reschedule') {
  query = `UPDATE appointments SET appointment_date = '${action.date}', appointment_time = '${action.time}', status = 'rescheduled', updated_at = NOW() WHERE id = '${action.appointment_id}' AND client_id = '${data.client_id}'`;
}

return [{ json: { ...data, appointment_query: query } }];

const data = $('7. Processar Resposta da IA').first().json;
const messages = data.response_messages || [];

// Simular delay entre mensagens (em produção, use Wait node)
const results = messages.map((msg, i) => ({
  json: {
    session_id: data.session_id,
    contact_phone: data.contact_phone,
    message_index: i,
    message_text: msg,
    delay_ms: (i + 1) * 2000,
    total_messages: messages.length
  }
}));

return results;

const raw = $input.first().json;
let arr = raw.body ?? raw;
if (typeof arr === 'string') {
  try { arr = JSON.parse(arr); } catch { arr = []; }
}
if (raw && typeof raw === 'object' && !Array.isArray(arr)) {
