parameters.jsCode:
const latest = $input.all()[0]?.json;
const currentExecId = $('Salvar no Buffer').item.json.execution_id;

const isNewest = latest?.execution_id === currentExecId;

return [{
  json: {
    isNewest: isNewest,
    telefone_cliente: latest?.telefone_cliente || '',
    execution_id: currentExecId
  }
}];

const items = $input.all();

const mensagens = items.map(item => {
  const { mensagem, tipo_midia, midia_url } = item.json;
  if (tipo_midia === 'imagem' && midia_url) {
    return '[Imagem enviada: ' + midia_url + ']';
  }
  return mensagem;
}).filter(m => m && m.trim());

const telefone = items[0]?.json.telefone_cliente || '';
const ids = items.map(i => i.json.id).filter(Boolean);
const temImagem = items.some(i => i.json.tipo_midia === 'imagem');
const urlsImagens = items
  .filter(i => i.json.tipo_midia === 'imagem' && i.json.midia_url)
  .map(i => i.json.midia_url);

return [{
  json: {
    mensagem_compilada: mensagens.join('\n'),
    telefone_cliente: telefone,
    ids_buffer: ids,
    quantidade_mensagens: mensagens.length,
    tem_imagem: temImagem,
    urls_imagens: urlsImagens
  }
}];

