parameters.jsCode:
return items.map(item => {
  const texto = item.json.answer || '';
  const match = texto.match(/https?:\/\/[^\s]+?\.(jpg|jpeg|png|gif)(\?[^\s]*)?/i);

  return {
    json: {
      imagem: match ? match[0] : null
    }
  };
});

const body = $input.first().json.body || $input.first().json;

const session_id = body.session_id || body.from || 'session-' + Date.now();
const contact_phone = body.phone || body.from || body.contact_phone || '';
const contact_name = body.name || body.contact_name || 'Cliente';
const message_type = body.type || body.message_type || 'text';
let message_content = '';

if (message_type === 'text') {
  message_content = body.text?.body || body.message || body.content || '';
} else if (message_type === 'image') {
  message_content = body.image?.url || body.media_url || '';
} else if (message_type === 'audio') {
  message_content = body.audio?.url || body.media_url || '';
}

return [{
  json: {
    session_id,
    contact_phone,
    contact_name,
    message_type,
    message_content,
    timestamp: new Date().toISOString()
  }
}];

const sessionRows = $('2. Verificar Modo Humano').all();
const inputData = $('Parsear Mensagem').first().json;

const sessionData = sessionRows.length > 0 ? sessionRows[0].json : {};
const humanTakeover = sessionData.human_takeover || false;
const takeoverAt = sessionData.takeover_at ? new Date(sessionData.takeover_at) : null;
const now = new Date();

let status = 'ia';

if (humanTakeover && takeoverAt) {
  const secondsElapsed = (now - takeoverAt) / 1000;
  if (secondsElapsed < 60) {
    status = 'human_active';
  } else {
    status = 'reset_to_ia';
  }
}

return [{
  json: {
    ...inputData,
    session_exists: !!sessionData.session_id,
    human_status: status
  }
}];

const clientRows = $('3. Verificar Cliente').all();
const inputData = $('Lógica Modo Humano').first().json;

let client_id = null;
let is_new_client = true;

if (clientRows.length > 0 && clientRows[0].json.id) {
  client_id = clientRows[0].json.id;
  is_new_client = false;
}

return [{
  json: {
    ...inputData,
    client_id,
    is_new_client
  }
}];

const inputData = $('Lógica Cliente Novo ou Existente').first().json;
let client_id = inputData.client_id;

try {
  const newClient = $('Cadastrar Novo Cliente').first();
  if (newClient?.json?.id) client_id = newClient.json.id;
} catch(e) {}

return [{ json: { ...inputData, client_id } }];

const historyRows = $('4. Carregar Histórico').all();
const inputData = $('Unificar client_id').first().json;

const history = historyRows
  .map(r => r.json)
  .reverse()
  .map(m => `${m.role === 'user' ? 'Cliente' : 'Assistente'}: ${m.content}`)
  .join('\n');

return [{ json: { ...inputData, conversation_history: history || 'Início da conversa.' } }];

const inputData = $('Formatar Histórico').first().json;
let processed_message = inputData.message_content;

try {
  const vision = $('Processar Imagem — Vision').first();
  if (vision?.json?.message?.content) {
    processed_message = '[Imagem recebida] ' + vision.json.message.content;
  }
} catch(e) {}

try {
  const whisper = $('Transcrever Áudio — Whisper').first();
  if (whisper?.json?.text) {
    processed_message = '[Áudio transcrito] ' + whisper.json.text;
  }
} catch(e) {}

return [{ json: { ...inputData, processed_message } }];

const aiData = $('6. Agente IA').first().json;
const inputData = $('Unificar Mensagem Processada').first().json;

const fullText = aiData.message?.content || aiData.choices?.[0]?.message?.content || 'Desculpe, não consegui processar.';

const needsHuman = fullText.includes('[HUMANO_NECESSÁRIO]');

let appointment_action = null;
const agendMatch = fullText.match(/\[AGENDAMENTO: especialidade=([^,]+), data=([\d-]+), horario=([\d:]+)\]/);
const cancelMatch = fullText.match(/\[CANCELAMENTO: appointment_id=([^\]]+)\]/);
const reagendMatch = fullText.match(/\[REAGENDAMENTO: appointment_id=([^,]+), data=([\d-]+), horario=([\d:]+)\]/);

if (agendMatch) {
  appointment_action = { type: 'schedule', specialty: agendMatch[1].trim(), date: agendMatch[2], time: agendMatch[3] };
} else if (cancelMatch) {
  appointment_action = { type: 'cancel', appointment_id: cancelMatch[1].trim() };
} else if (reagendMatch) {
  appointment_action = { type: 'reschedule', appointment_id: reagendMatch[1].trim(), date: reagendMatch[2], time: reagendMatch[3] };
}

const cleanText = fullText
  .replace('[HUMANO_NECESSÁRIO]', '')
  .replace(/\[AGENDAMENTO:[^\]]+\]/g, '')
  .replace(/\[CANCELAMENTO:[^\]]+\]/g, '')
  .replace(/\[REAGENDAMENTO:[^\]]+\]/g, '')
  .trim();

const messages = cleanText.split('[QUEBRA]').map(m => m.trim()).filter(Boolean);

return [{
  json: {
    ...inputData,
    ai_full_response: cleanText,
    response_messages: messages,
    needs_human: needsHuman,
    appointment_action
  }
}];

const data = $('7. Processar Resposta da IA').first().json;
const action = data.appointment_action;
let operation = '';
let fields = {};
let filter = '';

if (action.type === 'schedule') {
  operation = 'create';
  fields = {
    client_id: data.client_id,
    specialty: action.specialty,
    appointment_date: action.date,
    appointment_time: action.time,
    status: 'scheduled',
    created_at: new Date().toISOString()
  };
} else if (action.type === 'cancel') {
  operation = 'update';
  filter = `id=eq.${action.appointment_id}`;
  fields = { status: 'cancelled', updated_at: new Date().toISOString() };
} else if (action.type === 'reschedule') {
  operation = 'update';
  filter = `id=eq.${action.appointment_id}`;
  fields = {
    appointment_date: action.date,
    appointment_time: action.time,
    status: 'rescheduled',
    updated_at: new Date().toISOString()
  };
}

return [{ json: { ...data, appt_operation: operation, appt_fields: fields, appt_filter: filter } }];

const data = $('7. Processar Resposta da IA').first().json;
const messages = data.response_messages || [];

return messages.map((msg, i) => ({
  json: {
    session_id: data.session_id,
    contact_phone: data.contact_phone,
    message_index: i,
    message_text: msg,
    delay_ms: (i + 1) * 2000
  }
}));
